from agent import *from models.products import *def process_revlist(data, context, session):    revs = data.xpath("//h2[@class='post-box-title']/a")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url, use='curl'), process_review, dict(context, title=title, url=url))        nexturl = data.xpath("//span[@id='tie-next-page']/a/@href").string()    if nexturl:        session.queue(Request(nexturl, use='curl'), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context['title']    product.ssid = context['url'].split('/')[-2]    product.category = data.xpath("//nav[@id='crumbs']/following-sibling::a[last()-1]//text()").string()    product.url = context['url']        review = Review()    review.title = context['title']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    review.date = data.xpath("//p[@class='post-meta']/span[@class='tie-date']//text()").string()    pages = data.xpath("//div[@class='nav_link']/a[@class='page_number']")    for page in pages:        page_url = page.xpath("@href").string()        page_title = page.xpath(".//text()").string()        review.properties.append(ReviewProperty(type='pages', value={'url': page_url, 'title': product.name + ' - ' + page_title}))        if pages:        last_url = pages.last().xpath("@href").string()        session.do(Request(last_url, use='curl'), process_review_last, dict(context, product=product, review=review))    else:        context['product'] = product        context['review'] = review        process_review_last(data, context, session)        def process_review_last(data, context, session):    product = context['product']    review = context['review']        authors = data.xpath("//span[@class='post-meta-author']/a")    for author in authors:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        conclusion = data.xpath("//div[@class='split-container split-template-1']/h3[contains(.,'Conclusion')]/following-sibling::p[1]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='split-container split-template-1']/h3[contains(.,'Final Thoughts')]/following-sibling::p[1]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='entry']//p[1]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='entry']/h2[contains(.,'CONCLUSION')]/following-sibling::p[1]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='entry']/h2[contains(.,'Conclusion')]/following-sibling::p[1]").string(multiple=True)    if conclusion:        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))     if not conclusion:        excerpt = data.xpath("//div[@class='entry']/p//text()").string(multiple=True)        if not excerpt:            excerpt = data.xpath("//p[@class='content']//text()").string(multiple=True)        if not excerpt:            excerpt = data.xpath("//body//p//text()").string(multiple=True)        if excerpt:            review.properties.append(ReviewProperty(type='excerpt', value=excerpt))    grades = data.xpath("//div[@class='review-item']//text()")    grades_ok = True    for grade in grades:        grade = grade.string()        if grade:            if ' - ' in grade:                grade = grade.split(' - ')                if '%' in grade[1]:                    review.grades.append(Grade(name=grade[0], value=float(grade[1].replace('%', '')), best=100))                else:                    review.grades.append(Grade(name=grade[0], value=float(grade[1]), best=10.0))            else:                grades_ok = False                break    if not grades_ok:        grades = data.xpath("//div[@class='review-item']")        for grade in grades:            grade_name = grade.xpath("./h5//text()").string()            grade_val = grade.xpath(".//span/@style").string().split(':')[1].split('%')[0]            review.grades.append(Grade(name=grade_name, value=int(grade_val), best=100))    grade_overall = data.xpath("//div[@class='review-final-score']/h3//text()").string()    if grade_overall:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=10.0))        pros = data.xpath("//div[@class='split-container split-template-1']/p[contains(.,'Pro')]/following-sibling::ul[1]/li//text()")    if not pros:        pros = data.xpath("//*[contains(.,'Pro')]/following-sibling::ul[1]/li//text()")    for pro in pros:        pro = pro.string().replace('+', '').strip()        review.add_property(type='pros', value=pro)        cons = data.xpath("//div[@class='split-container split-template-1']/p[contains(.,'Con')]/following-sibling::ul[1]/li//text()")    if not cons:        cons = data.xpath("//*[contains(.,'Cons')]/following-sibling::ul[1]/li//text()")    for con in cons:        con = con.string().replace('- ', '').strip()        review.add_property(type='cons', value=con)        product.reviews.append(review)    session.emit(product)def run(context, session):    session.sessionbreakers=[SessionBreak(max_requests=10000)]    session.queue(Request('https://bjorn3d.com/category/reviews-articles/', use='curl'), process_revlist, {})